import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    try:
        q = int(next(it))
    except StopIteration:
        return
    # Node definition
    class Node:
        __slots__ = ('val','next')
        def __init__(self, val):
            self.val = val
            self.next = None
    head = None
    tail = None
    size = 0
    out_lines = []
    for _ in range(q):
        cmd = next(it)
        if cmd == 'ENQUEUE':
            x = int(next(it))
            node = Node(x)
            if tail is None:
                head = tail = node
            else:
                tail.next = node
                tail = node
            size += 1
        elif cmd == 'DEQUEUE':
            if head is None:
                out_lines.append('-1')
            else:
                out_lines.append(str(head.val))
                head = head.next
                if head is None:
                    tail = None
                size -= 1
        elif cmd == 'FRONT':
            if head is None:
                out_lines.append('-1')
            else:
                out_lines.append(str(head.val))
        elif cmd == 'SIZE':
            out_lines.append(str(size))
        elif cmd == 'EXIT':
            break
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

