#include <bits/stdc++.h>
using namespace std;
struct Node {
    long long val;
    Node* next;
    Node(long long v): val(v), next(nullptr) {}
};
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int Q;
    if(!(cin>>Q)) return 0;
    Node* head=nullptr;
    Node* tail=nullptr;
    int sz=0;
    string cmd;
    vector<string> out;
    for(int i=0;i<Q;++i){
        cin>>cmd;
        if(cmd=="ENQUEUE"){
            long long x;cin>>x;
            Node* node=new Node(x);
            if(tail==nullptr){
                head=tail=node;
            }else{
                tail->next=node;
                tail=node;
            }
            ++sz;
        }else if(cmd=="DEQUEUE"){
            if(head==nullptr){
                out.push_back("-1");
            }else{
                out.push_back(to_string(head->val));
                Node* tmp=head;
                head=head->next;
                delete tmp;
                if(head==nullptr) tail=nullptr;
                --sz;
            }
        }else if(cmd=="FRONT"){
            if(head==nullptr) out.push_back("-1");
            else out.push_back(to_string(head->val));
        }else if(cmd=="SIZE"){
            out.push_back(to_string(sz));
        }else if(cmd=="EXIT"){
            break;
        }
    }
    for(size_t i=0;i<out.size();++i){
        if(i) cout<<'\n';
        cout<<out[i];
    }
    return 0;
}
